import { db } from "@/app/utils/firebase";
import { collection, getDocs, addDoc, query } from "firebase/firestore";

export const getItem = async (userId) => {
  const item = [];

  const querySnapshot = await getDocs(
    collection(db, "users", userId, "items")
  );

  querySnapshot.forEach((doc) => {
    item.push({
      id: doc.id,
      ...doc.data(),
    });
  });

  return item;
};

export const addItem = async (userId, item) => {
  // references items 
  const itemsRefNum = collection(db, "users", userId, "items");
  // adds item as new document with autogenerated id
  const docRef = await addDoc(itemsRefNum, item);
  // return new created document id
  return docRef.id;
};